var PART_TOKEN = (process.env.NEXT_PUBLIC_PART_TOKEN_ADDRESS ?? "0xD95aC89029451c57Adf172192176d7264d49305a").toLowerCase();
var TREASURY = (process.env.TREASURY_ADDRESS ?? process.env.NEXT_PUBLIC_TREASURY_ADDRESS ?? "0x55B26f8CD67632d7AF9a888c645054Ca76E53455").toLowerCase();
var USDT_BSC = "0x55d398326f99059ff775485246999027b3197955";
var BSC_RPC = process.env.BSC_RPC_URL ?? "https://bsc-dataseed1.binance.org";
var TRANSFER_TOPIC = "0xddf252ad1be2c89b69c2b068fc378daa952ba7f163c4a11628f55a4df523b3ef";
async function verifyBscTx(txHash, currency) {
  try {
    const res = await fetch(BSC_RPC, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ jsonrpc: "2.0", method: "eth_getTransactionReceipt", params: [txHash], id: 1 })
    });
    const json = await res.json();
    const receipt = json.result;
    if (!receipt) return { ok: false, reason: "\u0130\u015Flem hen\xFCz onaylanmam\u0131\u015F" };
    if (receipt.status !== "0x1") return { ok: false, reason: "\u0130\u015Flem ba\u015Far\u0131s\u0131z (reverted)" };
    if (currency === "BNB") {
      const txRes = await fetch(BSC_RPC, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({ jsonrpc: "2.0", method: "eth_getTransactionByHash", params: [txHash], id: 2 })
      });
      const txJson = await txRes.json();
      const tx = txJson.result;
      if (!tx) return { ok: false, reason: "\u0130\u015Flem bulunamad\u0131" };
      if (tx.to?.toLowerCase() !== TREASURY) return { ok: false, reason: "Al\u0131c\u0131 treasury de\u011Fil" };
      return { ok: true };
    }
    const contractAddr = currency === "PART" ? PART_TOKEN : USDT_BSC;
    const transferLog = receipt.logs?.find(
      (l3) => l3.address?.toLowerCase() === contractAddr && l3.topics?.[0] === TRANSFER_TOPIC && `0x${l3.topics?.[2]?.slice(26)}`.toLowerCase() === TREASURY
    );
    if (!transferLog) return { ok: false, reason: `${currency} treasury transferi logda bulunamad\u0131` };
    return { ok: true };
  } catch (e5) {
    return { ok: false, reason: `RPC hatas\u0131: ${e5.message}` };
  }
}
