    if (!name?.trim()) return reply.code(400).send({ error: "name zorunlu" });
    const VALID_KINDS = ["avatar", "frame", "theme", "badge", "effect"];
    if (kind && !VALID_KINDS.includes(kind))
      return reply.code(400).send({ error: `kind \u015Funlardan biri olmal\u0131: ${VALID_KINDS.join(", ")}` });
