async function requireOwner(req, reply) {
  const userId = req.userId;
  if (!userId) {
    reply.code(401).send({ error: "Giris gerekli" });
    return void 0;
  }
  const user = await prisma.user.findUnique({ where: { id: userId }, select: { walletAddress: true } });
  if (!user?.walletAddress || user.walletAddress.toLowerCase() !== OWNER_ADDRESS) {
    reply.code(403).send({ error: "Bu panel yalnizca platform sahibine aciktir" });
    return void 0;
  }
  return userId;
}

// apps/api/src/services/price.ts
var KEY = "part_usd_rate";
var PART_USD_FLOOR = 0.01;
var DEFAULT_RATE = 0.01;
async function getPartUsdRate() {
  try {
    const row = await prisma.platformSetting.findUnique({ where: { key: KEY } });
    const v = row ? Number(row.value) : DEFAULT_RATE;
    return Number.isFinite(v) && v >= PART_USD_FLOOR ? v : DEFAULT_RATE;
  } catch {
    return DEFAULT_RATE;
  }
}
async function setPartUsdRate(rate) {
  if (!Number.isFinite(rate) || rate < PART_USD_FLOOR) {
    throw new Error(`Fiyat tabani ${PART_USD_FLOOR} altinda olamaz`);
  }
  await prisma.platformSetting.upsert({
    where: { key: KEY },
    create: { key: KEY, value: String(rate) },
    update: { value: String(rate) }
  });
  return { rate };
}

