// apps/api/src/routes/trending.ts
function velocityBoost(createdAt) {
  const ageHours = (Date.now() - createdAt.getTime()) / 36e5;
  if (ageHours < 2) return 2;
  if (ageHours < 6) return 1.5;
  if (ageHours < 12) return 1.2;
  return 1;
}
function trendScore(post) {
  const ageMs = Date.now() - post.createdAt.getTime();
  const ageHours = ageMs / 36e5;
  const gravity = Math.pow(ageHours + 2, 1.5);
  const engagementScore = post.likes + post.shares * 2 + post.comments * 3 + post.repostCount * 2.5 + post.saveCount * 2 + (post.views ?? 0) * 0.1 + (post.videoCompletion ?? 0) * 5;
  let boost = velocityBoost(post.createdAt);
  const mt = post.mediaType;
  if (mt === "video") boost *= 1.5;
  else if (mt === "audio") boost *= 1.2;
  else if (mt === "image") boost *= 1.1;
  if (post.author?.verified) boost *= 1.1;
  return engagementScore * boost / gravity;
}
async function registerTrendingRoutes(app) {
  app.get("/trending", async (req) => {
    const { limit = "10", window: window2 = "48" } = req.query;
    const take2 = Math.min(Number(limit), 50);
    const windowHrs = Math.min(Number(window2), 168);
    const [hashtags, rawPosts, trendingReels] = await Promise.all([
      /* Hashtag listesi: postCount'a göre sırala */
      prisma.hashtag.findMany({
        orderBy: { postCount: "desc" },
        take: 15,
        select: { id: true, tag: true, postCount: true }
      }),
      /* Son N saatteki gönderiler — score hesabı için geniş çek */
      prisma.post.findMany({
        where: { createdAt: { gte: new Date(Date.now() - windowHrs * 36e5) } },
        take: 200,
        include: {
          author: { select: { handle: true, name: true, avatarUrl: true, verified: true } },
          _count: { select: { commentList: true } }
        }
      }),
      /* Trending reels: views + likes */
      prisma.reel.findMany({
        where: { createdAt: { gte: new Date(Date.now() - windowHrs * 36e5) } },
        orderBy: [{ views: "desc" }, { likes: "desc" }],
        take: 10,
        include: { author: { select: { handle: true, name: true, avatarUrl: true, verified: true } } }
      })
    ]);
    const scored = rawPosts.map((p2) => ({
      ...p2,
      _trendScore: trendScore({
        ...p2,
        comments: p2._count.commentList,
        author: p2.author
      })
    })).sort((a5, b5) => b5._trendScore - a5._trendScore).slice(0, take2);
    const breakdown = {
      video: scored.filter((p2) => p2.mediaType === "video").length,
      image: scored.filter((p2) => p2.mediaType === "image").length,
      text: scored.filter((p2) => !p2.mediaType).length
    };
    return { hashtags, posts: scored, reels: trendingReels, breakdown, window: windowHrs };
  });
  app.get("/trending/summary", async () => {
    const hourAgo = new Date(Date.now() - 36e5);
    const dayAgo = new Date(Date.now() - 864e5);
    const [postsHour, postsDay, topHashtag, topReel] = await Promise.all([
      prisma.post.count({ where: { createdAt: { gte: hourAgo } } }),
      prisma.post.count({ where: { createdAt: { gte: dayAgo } } }),
      prisma.hashtag.findFirst({ orderBy: { postCount: "desc" }, select: { tag: true, postCount: true } }),
      prisma.reel.findFirst({
        orderBy: { views: "desc" },
        where: { createdAt: { gte: dayAgo } },
        select: { id: true, caption: true, views: true, likes: true }
      })
    ]);
    return { postsLastHour: postsHour, postsLast24h: postsDay, topHashtag, topReel };
  });
}
async function upsertHashtags(text, postId) {
  const tags = [...new Set((text.match(/#[\wÀ-ɏ]+/g) ?? []).map((t) => t.slice(1).toLowerCase()))];
  for (const tag2 of tags) {
    const ht = await prisma.hashtag.upsert({
      where: { tag: tag2 },
      update: { postCount: { increment: 1 } },
      create: { tag: tag2, postCount: 1 }
    });
    await prisma.postHashtag.upsert({
      where: { postId_hashtagId: { postId, hashtagId: ht.id } },
      update: {},
      create: { postId, hashtagId: ht.id }
    });
  }
}

// apps/api/src/routes/reposts.ts
async function registerRepostRoutes(app) {
  app.post("/posts/:id/repost", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id: postId } = req.params;
    const post = await prisma.post.findUnique({ where: { id: postId }, select: { authorId: true } });
    if (!post) return reply.code(404).send({ error: "Gonderi bulunamadi" });
    try {
      await prisma.repost.create({ data: { userId, postId } });
      await prisma.post.update({ where: { id: postId }, data: { repostCount: { increment: 1 } } });
      if (post.authorId !== userId) {
        await notify(post.authorId, "repost", "Gonderini biri yeniden paylasti");
      }
      return { reposted: true };
    } catch {
      return reply.code(409).send({ error: "Zaten yeniden paylasildi" });
    }
  });
  app.delete("/posts/:id/repost", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id: postId } = req.params;
    const deleted = await prisma.repost.deleteMany({ where: { userId, postId } });
    if (deleted.count > 0) {
      await prisma.post.update({ where: { id: postId }, data: { repostCount: { decrement: 1 } } });
    }
    return { reposted: false };
  });
  app.get("/posts/:id/reposts", async (req) => {
    const { id: postId } = req.params;
    const reposts = await prisma.repost.findMany({
      where: { postId },
      take: 50,
      orderBy: { createdAt: "desc" },
      include: { user: { select: { handle: true, name: true, avatarUrl: true, verified: true } } }
    });
    return { items: reposts };
  });
}

// apps/api/src/routes/message-reactions.ts
async function registerMessageReactionRoutes(app) {
  app.post("/messages/:id/react", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id: messageId } = req.params;
    const { emoji } = req.body;
    if (!emoji) return reply.code(400).send({ error: "emoji gerekli" });
    const msg = await prisma.message.findUnique({
      where: { id: messageId },
      select: { fromId: true, toId: true }
    });
    if (!msg) return reply.code(404).send({ error: "Mesaj bulunamadi" });
    const reaction = await prisma.messageReaction.upsert({
      where: { messageId_userId: { messageId, userId } },
      update: { emoji },
      create: { messageId, userId, emoji }
    });
    const otherId = msg.fromId === userId ? msg.toId : msg.fromId;
    deliverTo(otherId, { type: "dm_react", payload: { messageId, userId, emoji }, ts: Date.now() });
    return reaction;
  });
  app.delete("/messages/:id/react", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id: messageId } = req.params;
    await prisma.messageReaction.deleteMany({ where: { messageId, userId } });
    return { removed: true };
  });
  app.put("/messages/:id/seen", async (req, reply) => {
    const userId = requireAuth(req, reply);
    if (!userId) return;
    const { id: messageId } = req.params;
    const msg = await prisma.message.findUnique({ where: { id: messageId } });
    if (!msg) return reply.code(404).send({ error: "Mesaj bulunamadi" });
    if (msg.toId !== userId) return reply.code(403).send({ error: "Sadece alici okuyabilir" });
    await prisma.message.update({
      where: { id: messageId },
      data: { read: true, readAt: /* @__PURE__ */ new Date() }
    });
    deliverTo(msg.fromId, { type: "dm_seen", payload: { messageId, seenAt: /* @__PURE__ */ new Date() }, ts: Date.now() });
    return { seen: true };
  });
}

