function pickRandom(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}
function imageUrl(seed) {
  return `https://picsum.photos/seed/${seed}/${800 + Math.floor(Math.random() * 400)}/${400 + Math.floor(Math.random() * 300)}`;
}
async function buildPricePost() {
  try {
    const [part, bnb] = await Promise.all([getPartMarketData(), getBnbData()]);
    const coinFlip = Math.random() > 0.5;
    if (coinFlip) {
      const tmpl = pickRandom(TEMPLATES.part_price);
      const change = part.priceChange24h >= 0 ? `+${part.priceChange24h.toFixed(2)}% 24 saatte \u{1F4C8}` : `${part.priceChange24h.toFixed(2)}% 24 saatte \u{1F4C9}`;
      return tmpl.replace("{PRICE}", part.priceUsd.toFixed(4)).replace("{CHANGE}", change);
    } else {
      const tmpl = pickRandom(TEMPLATES.bnb_price);
      return tmpl.replace("{PRICE}", bnb.priceUsd.toFixed(2));
    }
  } catch {
    return pickRandom(TEMPLATES.saphara_promo).replace("{FOLLOWERS}", String(Math.floor(Math.random() * 900 + 100))).replace("{POSTS}", String(Math.floor(Math.random() * 50 + 10)));
  }
}
async function buildNewsPost() {
  try {
    const cat = Math.random() > 0.5 ? "crypto" : "technology";
    const news = await getNews(cat);
    if (news.length > 0) {
      const item = pickRandom(news.slice(0, 10));
      const tmpl = cat === "crypto" ? pickRandom(TEMPLATES.crypto_news) : pickRandom(TEMPLATES.general_news);
      const title = item.title.slice(0, 100);
      return {
        text: tmpl.replace("{TITLE}", title),
        mediaUrl: item.imageUrl
      };
    }
  } catch {
  }
  return { text: pickRandom(TEMPLATES.lifestyle) };
}
async function createBotPost(botId) {
  const strategy = Math.random();
  let text;
  let mediaUrl;
  if (strategy < 0.3) {
    text = await buildPricePost();
    if (Math.random() > 0.6) mediaUrl = imageUrl(`price_${Date.now()}`);
  } else if (strategy < 0.55) {
    const result = await buildNewsPost();
    text = result.text;
    mediaUrl = result.mediaUrl ?? (Math.random() > 0.5 ? imageUrl(`news_${Date.now()}`) : void 0);
  } else if (strategy < 0.75) {
    text = pickRandom(TEMPLATES.saphara_promo).replace("{FOLLOWERS}", String(Math.floor(Math.random() * 900 + 100))).replace("{POSTS}", String(Math.floor(Math.random() * 50 + 10)));
    if (Math.random() > 0.4) mediaUrl = imageUrl(`promo_${Date.now()}`);
  } else {
    text = pickRandom(TEMPLATES.lifestyle);
    if (Math.random() > 0.5) mediaUrl = imageUrl(`life_${Date.now()}`);
  }
  const post = await prisma.post.create({
    data: {
      authorId: botId,
      text,
      mediaUrl,
      mediaType: mediaUrl ? "image" : void 0,
      likes: Math.floor(Math.random() * 200),
      repostCount: Math.floor(Math.random() * 50),
      qualityScore: 0.4 + Math.random() * 0.5
    }
  });
  await upsertHashtags(text, post.id);
}
function startContentBot() {
  const intervalMs = Number(process.env.BOT_POST_INTERVAL_MS ?? "1800000");
  const postsPerCycle = Number(process.env.BOT_POSTS_PER_CYCLE ?? "3");
  const runCycle = async () => {
    try {
      const bots = await prisma.user.findMany({
        where: {
          handle: { contains: "_" },
          walletAddress: { startsWith: "0x0000" }
        },
        select: { id: true },
        take: 200
      });
      if (bots.length === 0) return;
      const selected = bots.sort(() => Math.random() - 0.5).slice(0, postsPerCycle);
      await Promise.allSettled(selected.map((b5) => createBotPost(b5.id)));
    } catch (e5) {
      const msg = e5?.message ?? "";
      if (msg.includes("Can't reach database") || msg.includes("ECONNREFUSED")) return;
      console.error("[ContentBot] Hata:", e5);
    }
  };
  const first = setTimeout(() => {
    runCycle();
    const interval = setInterval(runCycle, intervalMs);
    interval.unref();
  }, 2 * 60 * 1e3);
  first.unref();
  console.log(`[ContentBot] Ba\u015Flat\u0131ld\u0131 \u2014 her ${intervalMs / 6e4} dakikada ${postsPerCycle} g\xF6nderi`);
}
async function runBotCycleOnce(count = 5) {
  const bots = await prisma.user.findMany({
    where: { walletAddress: { startsWith: "0x0000" } },
    select: { id: true },
    take: 200
  });
  if (bots.length === 0) return 0;
  const selected = bots.sort(() => Math.random() - 0.5).slice(0, count);
  const results = await Promise.allSettled(selected.map((b5) => createBotPost(b5.id)));
  return results.filter((r5) => r5.status === "fulfilled").length;
}

